/**
 * 规则：任一 keyword 在近期消息中出现 → 所有「条目名包含 entryNameIncludes」的已启用条目改为 constant；
 * 否则改为 selective（不改变 enabled、不改变 keys）。
 */
type KeywordWorldbookRule = {
  keywords: string[];
  // 当 scanMode=location+recent / location+last 时，位置命中的关键词（可不填，默认使用 keywords）
  locationKeywords?: string[];
  entryNameIncludes: string;
  // 命中 keyword 时，把对应条目切到哪种灯
  hitType?: 'constant' | 'selective';
  // 未命中（或已连续 misses>=3）时，把对应条目切到哪种灯
  missType?: 'constant' | 'selective';
  // 只看哪些文本来源：
  // recent=扫描最近多条；last=只看最后一条消息；location=只看世界.当前位置
  // location+recent=位置命中 + 近期关键词同时命中（用户与 AI 消息都算）
  // location+userRecent=位置命中 + 近期关键词仅统计「用户发出」的消息（AI 回复里出现不算）
  // location+last=位置命中 + 最后一条关键词同时命中
  // location|recent=位置命中 或 近期关键词命中（任一成立）
  scanMode?: 'recent' | 'last' | 'location' | 'location+recent' | 'location+userRecent' | 'location+last' | 'location|recent';
  // 连续未命中多少次就强制走 missType（默认 3；设为 1 可实现“只触发当前楼层”）
  missThreshold?: number;
};

