/* ============================================================================
 * 【Dark 战斗风格 × 委托】不用写 RULES。
 * 世界书条目名需匹配：{剑圣|枪神|骗术师|皇家护卫|皇家守卫}风格{1|2|3|4}
 * （1=α … 4=δ，与 src/Dark 主角.风格阶位 一致）。
 * 亮灯标签真源：主角.战斗风格 + 主角.风格阶位[该风格] →「枪神风格2」；与世界书条目名一致且 hasQuestContextForCombatStyleEntries 成立则蓝灯。
 * 读不到 战斗风格 时才用 当前风格 / 旧键当前风格条目。Dark 每次合并用 战斗风格+阶位 回写 当前风格（展示/变量导出用）。
 * ============================================================================ */

/** 避免「剑圣风格12」被误识别为「剑圣风格1」
 * 同时兼容：空格 / 全角数字 / 中文数字（一二三四）
 */
const COMBAT_STYLE_QUEST_ENTRY_RE =
  /(剑圣|枪神|骗术师|皇家护卫|皇家守卫)风格\s*([1-4]|[１-４]|[一二三四])(?![0-9])/;

function parseCombatStyleQuestEntryName(name: string): { style: string; tier: number } | null {
  const m = String(name || '').match(COMBAT_STYLE_QUEST_ENTRY_RE);
  if (!m) return null;
  let style = m[1];
  if (style === '皇家守卫') style = '皇家护卫';

  const tierRaw = m[2];
  // 中文/全角数字统一映射到 1~4
  const tier =
    tierRaw === '一' || tierRaw === '１'
      ? 1
      : tierRaw === '二' || tierRaw === '２'
        ? 2
        : tierRaw === '三' || tierRaw === '３'
          ? 3
          : tierRaw === '四' || tierRaw === '４'
            ? 4
            : Number(tierRaw);
  if (!Number.isFinite(tier)) return null;
  return { style, tier };
}

function isCombatStyleQuestManagedEntry(entryName: string): boolean {
  return parseCombatStyleQuestEntryName(entryName) !== null;
}

function normalizeDarkCombatStyle(raw: string): string {
  const s = String(raw || '').trim();
  if (s === '皇家守卫') return '皇家护卫';
  if (s === '骗术师' || s === '剑圣' || s === '皇家护卫' || s === '枪神') return s;
  return '';
}

function clampDarkStyleTier(n: unknown): number {
  const v = Math.round(Number(n));
  if (!Number.isFinite(v)) return 1;
  return Math.max(1, Math.min(4, v));
}

/** 内层 stat_data、display、根对象合并后的 主角 快照（与 Dark / MVU 多层结构一致） */
function mergeProtagonistLayer(candidate: any): Record<string, unknown> {
  if (!candidate || typeof candidate !== 'object') return {};
  const sd = candidate.stat_data;
  const inner = sd && typeof sd === 'object' && sd.stat_data && typeof sd.stat_data === 'object' ? sd.stat_data : null;
  const dispRoot = candidate.display_data?.主角;
  const dispSd = sd && typeof sd === 'object' ? sd.display_data?.主角 : undefined;
  return {
    ...(inner?.主角 || {}),
    ...(typeof dispRoot === 'object' && dispRoot ? dispRoot : {}),
    ...(typeof dispSd === 'object' && dispSd ? dispSd : {}),
    ...(candidate.主角 || {}),
    ...(candidate.mvu?.主角 || {}),
    ...(sd && typeof sd === 'object' && sd.主角 ? sd.主角 : {}),
  } as Record<string, unknown>;
}

function extractRawProtagonistStyleLabelFromShape(candidate: any): string {
  const merge主角 = mergeProtagonistLayer(candidate);
  const cur = merge主角['当前风格'];
  const legacy = merge主角['当前风格条目'];
  const raw = (typeof cur === 'string' ? cur : '') || (typeof legacy === 'string' ? legacy : '');
  return raw.trim();
}

function extractProtagonistStyleFromShape(candidate: any): { style: string; ranks: Record<string, unknown> } | null {
  if (!candidate || typeof candidate !== 'object') return null;
  const merge主角 = mergeProtagonistLayer(candidate);
  const styleRaw = merge主角.战斗风格;
  const style = typeof styleRaw === 'string' ? styleRaw.trim() : '';
  const ranksRaw = merge主角.风格阶位;
  const ranks =
    ranksRaw && typeof ranksRaw === 'object' && !Array.isArray(ranksRaw)
      ? (ranksRaw as Record<string, unknown>)
      : {};
  if (!style && Object.keys(ranks).length === 0) return null;
  return { style, ranks };
}

const PROTAGONIST_VARIABLE_SCOPES: Array<Parameters<typeof getVariables>[0]> = [
  { type: 'message', message_id: 'latest' },
  { type: 'chat' },
  { type: 'character' },
  { type: 'global' },
];

function getProtagonistCombatStyleAndRanks(): { style: string; ranks: Record<string, unknown> } {
  // Dark iframe 里切风格后，会通过 mirrorStatDataToChat 把楼层 stat_data 镜像到 `getVariables({type:'chat'})`。
  // 相比之下，Mvu.getMvuData(message.latest) 有时会滞后一拍；所以这里优先读 chat，避免读到旧快照。
  for (const scope of PROTAGONIST_VARIABLE_SCOPES) {
    try {
      const v = getVariables(scope) as any;
      const hit = extractProtagonistStyleFromShape(v);
      if (hit?.style) return { style: hit.style, ranks: hit.ranks };
    } catch {
      /* ignore */
    }
  }

  try {
    const g = globalThis as any;
    if (g?.Mvu && typeof g.Mvu.getMvuData === 'function') {
      const byLatest = g.Mvu.getMvuData({ type: 'message', message_id: 'latest' });
      const hitL = extractProtagonistStyleFromShape(byLatest);
      if (hitL?.style) return { style: hitL.style, ranks: hitL.ranks };

      const lastId = getLastMessageId();
      if (lastId >= 0) {
        const byId = g.Mvu.getMvuData({ type: 'message', message_id: lastId });
        const hitI = extractProtagonistStyleFromShape(byId);
        if (hitI?.style) return { style: hitI.style, ranks: hitI.ranks };
      }
    }
  } catch {
    /* ignore */
  }

  return { style: '', ranks: {} };
}

/** 战斗风格世界书：以 战斗风格+阶位 为真源（与 Dark 回写 当前风格 一致）；仅当读不到战斗风格时才用 当前风格 / 旧键兜底 */
function getProtagonistCurrentStyleLabelForWorldbook(): string {
  const { style, ranks } = getProtagonistCombatStyleAndRanks();
  const canon = normalizeDarkCombatStyle(style);
  if (canon) return `${canon}风格${clampDarkStyleTier(ranks[canon])}`;

  const tryShape = (candidate: any): string => {
    const raw = extractRawProtagonistStyleLabelFromShape(candidate);
    if (!raw) return '';
    return parseCombatStyleQuestEntryName(raw) ? raw : '';
  };
  try {
    const g = globalThis as any;
    if (g?.Mvu && typeof g.Mvu.getMvuData === 'function') {
      const byLatest = g.Mvu.getMvuData({ type: 'message', message_id: 'latest' });
      const a = tryShape(byLatest);
      if (a) return a;
      const lastId = getLastMessageId();
      if (lastId >= 0) {
        const byId = g.Mvu.getMvuData({ type: 'message', message_id: lastId });
        const b = tryShape(byId);
        if (b) return b;
      }
    }
  } catch {
    /* ignore */
  }
  for (const scope of PROTAGONIST_VARIABLE_SCOPES) {
    try {
      const v = getVariables(scope) as any;
      const c = tryShape(v);
      if (c) return c;
    } catch {
      /* ignore */
    }
  }
  return '';
}

/** 战斗风格条目蓝灯：变量里未必写「委托状态」= 精确「执行中」，需兼容「进行中」等子串及空字段时靠 当前委托等级+地点 兜底（见 getWorldQuestStatus） */
function isQuestActiveForCombatStyleEntries(questStatus: string): boolean {
  const s = String(questStatus || '').trim();
  if (s === '执行中') return true;
  if (!s) return false;
  if (/结束|已完成|已结束|取消|失效/i.test(s)) return false;
  if (/执行|进行中|承接|进行/i.test(s)) return true;
  return false;
}

let debounceTimer: ReturnType<typeof setTimeout> | null = null;
let lastWorldbookWarn: string | null = null;

/** 避免 Mvu 晚于本脚本加载时重复注册 */
let mvuVariableEndedListenerAttached = false;

function attachMvuVariableEndedListenerOnce(): void {
  if (mvuVariableEndedListenerAttached) {
    return;
  }
  const g = globalThis as any;
  const ev = g.Mvu?.events?.VARIABLE_UPDATE_ENDED;
  if (typeof ev !== 'string') {
    return;
  }
  try {
    eventOn(ev, () => {
      kwLog('VARIABLE_UPDATE_ENDED → 调度同步');
      scheduleSync();
    });
    mvuVariableEndedListenerAttached = true;
    kwLog('已监听 Mvu VARIABLE_UPDATE_ENDED（面板/解析改变量后会同步世界书）');
  } catch (e) {
    console.warn('[关键字世界书] VARIABLE_UPDATE_ENDED 注册失败', e);
  }
}

