/** 当前角色绑定的主世界书；未绑定则返回 null */
function resolvePrimaryWorldbookName(): string | null {
  try {
    const { primary } = getCharWorldbookNames('current');
    const n = primary?.trim();
    return n ? n : null;
  } catch (e) {
    console.warn('[关键字世界书] getCharWorldbookNames 失败', e);
    return null;
  }
}

function stripMessageNoise(raw: string): string {
  let t = raw;
  t = t.replace(/```[\s\S]*?```/g, ' ');
  t = t.replace(/<UpdateVariable>[\s\S]*?<\/UpdateVariable>/gi, ' ');
  return t;
}

/** 取近期纯文本（去掉代码块，减轻误匹配） */
function getRecentMessageTexts(maxMessages: number): string[] {
  try {
    const last = getLastMessageId();
    if (last < 0) return [];
    const all = getChatMessages(`0-${last}`);
    const slice = all.slice(Math.max(0, all.length - maxMessages));
    return slice
      .map(m => stripMessageNoise(m.message ?? ''))
      .map(t => t.trim())
      .filter(Boolean);
  } catch (e) {
    console.warn('[关键字世界书] 获取消息失败', e);
    return [];
  }
}

/** 仅用户发送的近期消息文本（不含 AI 回复），用于「只有玩家输入里带关键词才命中」 */
function getRecentUserMessageTexts(maxMessages: number): string[] {
  try {
    const last = getLastMessageId();
    if (last < 0) return [];
    const all = getChatMessages(`0-${last}`, { role: 'user' });
    const slice = all.slice(Math.max(0, all.length - maxMessages));
    return slice
      .map(m => stripMessageNoise(m.message ?? ''))
      .map(t => t.trim())
      .filter(Boolean);
  } catch (e) {
    console.warn('[关键字世界书] 获取用户消息失败', e);
    return [];
  }
}

function keywordHitInTexts(texts: string[], keywords: string[]): boolean {
  for (const kw of keywords) {
    const k = kw.trim();
    if (!k) continue;
    for (const t of texts) {
      if (t.includes(k)) return true;
    }
  }
  return false;
}

function formatScopeLabel(scope: Parameters<typeof getVariables>[0]): string {
  if (scope.type === 'message') return 'message/latest';
  return scope.type;
}

function extractWorldTextFromCandidate(candidate: any, key: string): string {
  if (!candidate || typeof candidate !== 'object') return '';
  const raw = candidate?.世界?.[key];
  if (typeof raw !== 'string') return '';
  return raw.trim();
}

function extractWorldTextFromAnyShape(candidate: any, key: string): string {
  // 兼容多种结构：root / stat_data / mvu；并合并「内层 stat_data / display_data」（MVU 常在 stat_data 里再套一层，外层 世界 与内层可能不一致）
  const sd = candidate?.stat_data;
  const inner = sd && typeof sd === 'object' && sd.stat_data && typeof sd.stat_data === 'object' ? sd.stat_data : null;
  const merged = {
    ...(candidate || {}),
    ...(sd || {}),
    世界: {
      ...(inner?.世界 || {}),
      ...(outerDisplayWorld(sd) || {}),
      ...(candidate?.display_data?.世界 || {}),
      ...(candidate?.世界 || {}),
      ...(sd?.世界 || {}),
    },
  };
  const fromMerged = extractWorldTextFromCandidate(merged, key);
  if (fromMerged) return fromMerged;

  const mvu = extractWorldTextFromCandidate(candidate?.mvu, key);
  if (mvu) return mvu;

  return '';
}

function outerDisplayWorld(sd: any): Record<string, unknown> | undefined {
  const d = sd?.display_data;
  return d && typeof d === 'object' && d.世界 && typeof d.世界 === 'object' ? (d.世界 as Record<string, unknown>) : undefined;
}

/** 最近一条消息（可能是用户或 AI）的纯文本 */
function getLastAnyMessageText(): string {
  try {
    const lastId = getLastMessageId();
    if (lastId < 0) return '';
    const all = getChatMessages(`0-${lastId}`);
    const lastMsg = all[all.length - 1];
    let t = lastMsg?.message ?? '';
    t = t.replace(/```[\s\S]*?```/g, ' ');
    t = t.replace(/<UpdateVariable>[\s\S]*?<\/UpdateVariable>/gi, ' ');
    return String(t || '').trim();
  } catch (e) {
    console.warn('[关键字世界书] getLastAnyMessageText failed', e);
    return '';
  }
}

/** 取“最近一次收到的 AI 回复”的纯文本（尽量去掉代码块，减轻误判） */
function getLastReceivedText(): string {
  try {
    const lastId = getLastMessageId();
    if (lastId < 0) return '';
    const all = getChatMessages(`0-${lastId}`);
    const lastMsg = all[all.length - 1];
    let t = lastMsg?.message ?? '';
    t = t.replace(/```[\s\S]*?```/g, ' ');
    t = t.replace(/<UpdateVariable>[\s\S]*?<\/UpdateVariable>/gi, ' ');
    return String(t || '').trim();
  } catch (e) {
    console.warn('[关键字世界书] getLastReceivedText failed', e);
    return '';
  }
}

/** 更新每条 RULE 的“连续未命中计数”（只统计 AI 回复：MESSAGE_RECEIVED） */
function updateMissingCountsByLastReceived(): void {
  try {
    const lastId = getLastMessageId();
    if (lastId === lastHandledReceivedMessageId) return; // 防止重复触发同一条回复
    lastHandledReceivedMessageId = lastId;

    const lastText = getLastReceivedText();
    RULES.forEach((rule, idx) => {
      const hit = keywordHitInTexts([lastText], rule.keywords);
      if (hit) missingCountByRule[idx] = 0;
      else missingCountByRule[idx] += 1;
    });
  } catch (e) {
    console.warn('[关键字世界书] updateMissingCountsByLastReceived failed', e);
  }
}

/** 更新每条 RULE 的“连续未命中计数”（统计最后一条消息：可能是用户或 AI） */
function updateMissingCountsByLastAnyMessage(): void {
  try {
    const lastId = getLastMessageId();
    if (lastId === lastHandledAnyMessageId) return; // 防止同一条消息重复推进
    lastHandledAnyMessageId = lastId;

    const lastText = getLastAnyMessageText();
    RULES.forEach((rule, idx) => {
      // 只有 scanMode=last 的规则才用“最后一条消息”推进 missCount
      if ((rule.scanMode ?? 'recent') !== 'last') return;
      const hit = keywordHitInTexts([lastText], rule.keywords);
      if (hit) missingCountByRule[idx] = 0;
      else missingCountByRule[idx] += 1;
    });
  } catch (e) {
    console.warn('[关键字世界书] updateMissingCountsByLastAnyMessage failed', e);
  }
}

type KeywordScanContext = {
  recentTexts: string[];
  /** 仅用户消息，供 location+userRecent */
  recentUserTexts: string[];
  lastTexts: string[];
  worldLocation: string;
};

function getTextsByScanMode(
  mode: NonNullable<KeywordWorldbookRule['scanMode']>,
  ctx: KeywordScanContext,
): string[] {
  if (mode === 'last') return ctx.lastTexts;
  if (mode === 'location') return ctx.worldLocation ? [ctx.worldLocation] : [];
  if (mode === 'location+last') return ctx.lastTexts;
  if (mode === 'location+recent') return ctx.recentTexts;
  if (mode === 'location+userRecent') return ctx.recentUserTexts;
  if (mode === 'location|recent') return ctx.recentTexts;
  return ctx.recentTexts;
}

function ruleHitByMode(rule: KeywordWorldbookRule, ctx: KeywordScanContext): boolean {
  const mode = rule.scanMode ?? 'recent';
  if (mode === 'location+recent') {
    const locationWords = rule.locationKeywords?.length ? rule.locationKeywords : rule.keywords;
    const locationHit = keywordHitInTexts(ctx.worldLocation ? [ctx.worldLocation] : [], locationWords);
    const keywordHit = keywordHitInTexts(ctx.recentTexts, rule.keywords);
    return locationHit && keywordHit;
  }
  if (mode === 'location+userRecent') {
    const locationWords = rule.locationKeywords?.length ? rule.locationKeywords : rule.keywords;
    const locationHit = keywordHitInTexts(ctx.worldLocation ? [ctx.worldLocation] : [], locationWords);
    const keywordHit = keywordHitInTexts(ctx.recentUserTexts, rule.keywords);
    return locationHit && keywordHit;
  }
  if (mode === 'location+last') {
    const locationWords = rule.locationKeywords?.length ? rule.locationKeywords : rule.keywords;
    const locationHit = keywordHitInTexts(ctx.worldLocation ? [ctx.worldLocation] : [], locationWords);
    const keywordHit = keywordHitInTexts(ctx.lastTexts, rule.keywords);
    return locationHit && keywordHit;
  }
  if (mode === 'location|recent') {
    const locationWords = rule.locationKeywords?.length ? rule.locationKeywords : rule.keywords;
    const locationHit = keywordHitInTexts(ctx.worldLocation ? [ctx.worldLocation] : [], locationWords);
    const keywordHit = keywordHitInTexts(ctx.recentTexts, rule.keywords);
    return locationHit || keywordHit;
  }
  return keywordHitInTexts(getTextsByScanMode(mode, ctx), rule.keywords);
}

function getNextStrategyTypeForEntry(entryName: string, ctx: KeywordScanContext): WorldbookEntry['strategy']['type'] | null {
  // 一个 entryName 只会匹配一个 entryNameIncludes（按你的命名习惯）
  const matchedRuleIdx = RULES.findIndex(r => r.entryNameIncludes && entryName.includes(r.entryNameIncludes));
  if (matchedRuleIdx < 0) return null;
  const rule = RULES[matchedRuleIdx];

  const hit = ruleHitByMode(rule, ctx);
  const threshold = rule.missThreshold ?? 3;
  const tooManyMisses = threshold > 0 ? (missingCountByRule[matchedRuleIdx] ?? 0) >= threshold : false;

  // 命中：切到 hitType（例如 selective=绿色）
  if (hit && !tooManyMisses) {
    return (rule.hitType ?? 'constant') as WorldbookEntry['strategy']['type'];
  }
  // 未命中 / misses>=3：切到 missType
  return (rule.missType ?? 'selective') as WorldbookEntry['strategy']['type'];
}

/** 该条目是否受本脚本管理（名称命中任一规则的 entryNameIncludes） */
function isManagedEntry(entryName: string): boolean {
  if (entryName.includes('猎人等级-')) return true;
  if (entryName.includes('当前委托状态') || entryName.includes('委托完成检测')) return true;
  if (isCombatStyleQuestManagedEntry(entryName)) return true;
  if (isRaceManagedEntry(entryName)) return true;
  return RULES.some(r => r.entryNameIncludes && entryName.includes(r.entryNameIncludes));
}

function getWorldTextByKey(key: string): string {
  // 1) 先试 Mvu.getMvuData（和状态栏读取逻辑保持一致）
  try {
    const g = globalThis as any;
    if (g?.Mvu && typeof g.Mvu.getMvuData === 'function') {
      const byLatest = g.Mvu.getMvuData({ type: 'message', message_id: 'latest' });
      const tLatest = extractWorldTextFromAnyShape(byLatest, key);
      if (tLatest) {
        kwTrace(`读取 世界.${key} 命中来源=Mvu.getMvuData(message.latest) 值=${tLatest}`);
        return tLatest;
      }
      const lastId = getLastMessageId();
      if (lastId >= 0) {
        const byId = g.Mvu.getMvuData({ type: 'message', message_id: lastId });
        const tById = extractWorldTextFromAnyShape(byId, key);
        if (tById) {
          kwTrace(`读取 世界.${key} 命中来源=Mvu.getMvuData(message.${String(lastId)}) 值=${tById}`);
          return tById;
        }
      }
    }
  } catch {
    // ignore and fallback
  }

  // 2) 再试 getVariables 的多层作用域
  const scopes: Array<Parameters<typeof getVariables>[0]> = [
    { type: 'message', message_id: 'latest' },
    { type: 'chat' },
    { type: 'character' },
    { type: 'global' },
  ];
  for (const scope of scopes) {
    try {
      const v = getVariables(scope) as any;
      const t = extractWorldTextFromAnyShape(v, key);
      if (t) {
        kwTrace(`读取 世界.${key} 命中来源=getVariables(${formatScopeLabel(scope)}) 值=${t}`);
        return t;
      }
    } catch {
      // ignore and continue fallback
    }
  }
  kwTrace(`读取 世界.${key} 失败：所有层都为空`);
  return '';
}

/** 战斗风格类世界书：除 isQuestActiveForCombatStyleEntries 外，「当前委托内容」非空也视为已接任务 */
function hasQuestContextForCombatStyleEntries(questStatus: string): boolean {
  if (isQuestActiveForCombatStyleEntries(questStatus)) return true;
  const body = getWorldTextByKey('当前委托内容').trim();
  if (body.length > 0) {
    kwTrace('战斗风格×委托：当前委托内容非空，视为有任务');
    return true;
  }
  return false;
}

function getStrategyTypeForCombatStyleQuestEntry(
  entryName: string,
  activeStyleRaw: string,
  ranks: Record<string, unknown>,
  questStatus: string,
  currentStyleLabel: string,
): WorldbookEntry['strategy']['type'] | null {
  const parsed = parseCombatStyleQuestEntryName(entryName);
  if (!parsed) return null;

  const label = String(currentStyleLabel || '').trim();
  if (label) {
    const pl = parseCombatStyleQuestEntryName(label);
    if (pl) {
      if (!hasQuestContextForCombatStyleEntries(questStatus)) {
        return 'selective';
      }
      const byLabel = pl.style === parsed.style && pl.tier === parsed.tier;
      return byLabel ? 'constant' : 'selective';
    }
  }

  const activeCanon = normalizeDarkCombatStyle(activeStyleRaw);
  const entryStyleCanon = parsed.style;
  const rankForActiveStyle = activeCanon ? clampDarkStyleTier(ranks[activeCanon]) : 1;

  const shouldBlue =
    hasQuestContextForCombatStyleEntries(questStatus) &&
    Boolean(activeCanon) &&
    activeCanon === entryStyleCanon &&
    rankForActiveStyle === parsed.tier;

  return shouldBlue ? 'constant' : 'selective';
}

function getWorldHunterLevel(): string {
  return getWorldTextByKey('猎人等级');
}

function getWorldLocation(): string {
  return getWorldTextByKey('当前位置');
}

function getWorldQuestStatus(): string {
  // 优先取正式字段，其次兼容历史命名
  const keyCandidates = ['委托状态', '当前委托状态', '委托执行状态'];
  for (const key of keyCandidates) {
    const v = getWorldTextByKey(key);
    if (v) {
      kwTrace(`委托状态字段命中 key=${key} value=${v}`);
      return v;
    }
  }

  // 兜底1：如果变量层拿不到，尝试从最新楼层文案推断
  const lastText = getLastAnyMessageText();
  if (/委托状态?[:：]\s*执行中/.test(lastText) || /委托[:：]\s*执行中/.test(lastText)) {
    kwTrace('委托状态兜底命中：从最后一条消息推断为 执行中');
    return '执行中';
  }
  if (/委托状态?[:：]\s*委托结束/.test(lastText) || /委托状态?[:：]\s*已结束/.test(lastText) || /委托[:：]\s*委托结束/.test(lastText) || /委托[:：]\s*已结束/.test(lastText)) {
    kwTrace('委托状态兜底命中：从最后一条消息推断为 委托结束');
    return '委托结束';
  }

  // 兜底2：再扫最近多条消息（有些“执行中”不在最后一条）
  const recentTexts = getRecentMessageTexts(SCAN_LAST_MESSAGES);
  const recentCombined = recentTexts.join('\n');
  if (/委托状态?[:：]\s*执行中/.test(recentCombined) || /委托[:：]\s*执行中/.test(recentCombined)) {
    kwTrace('委托状态兜底命中：从近期消息推断为 执行中');
    return '执行中';
  }
  if (/委托状态?[:：]\s*委托结束/.test(recentCombined) || /委托状态?[:：]\s*已结束/.test(recentCombined) || /委托[:：]\s*委托结束/.test(recentCombined) || /委托[:：]\s*已结束/.test(recentCombined)) {
    kwTrace('委托状态兜底命中：从近期消息推断为 委托结束');
    return '委托结束';
  }

  // 兜底3：如果“当前委托等级 + 当前委托地点”存在，默认按“执行中”处理
  const questGrade = getWorldTextByKey('当前委托等级');
  const questLocation = getWorldTextByKey('当前委托地点');
  if (questGrade && questLocation) {
    kwTrace(`委托状态兜底命中：检测到当前委托(${questGrade}/${questLocation})，默认执行中`);
    return '执行中';
  }
  return '';
}

function normalizeCharacterMap(raw: unknown): Record<string, any> | null {
  if (!raw) return null;
  if (typeof raw === 'object' && !Array.isArray(raw)) return raw as Record<string, any>;
  if (typeof raw === 'string') {
    try {
      const p = JSON.parse(raw);
      if (p && typeof p === 'object' && !Array.isArray(p)) return p as Record<string, any>;
    } catch {
      /* ignore */
    }
  }
  return null;
}

function pushRaceStringsFromCharacterMap(map: Record<string, any> | null, out: string[]): void {
  if (!map) return;
  for (const key of Object.keys(map)) {
    const r = map[key]?.种族;
    if (typeof r === 'string' && r.trim()) out.push(r.trim());
  }
}

/**
 * 从一层变量表里收集「种族」字符串。
 * 注意：MVU / 部分界面会把「当前互动角色」挂在根或 stat_data 下，而不是 主角.当前互动角色（与 src/Dark 合并逻辑一致）。
 */
function collectRaceStringsFromVariableRoot(v: any): string[] {
  const out: string[] = [];
  const merge主角 = { ...(v?.主角 || {}), ...(v?.stat_data?.主角 || {}) };

  // 主角.当前互动角色
  pushRaceStringsFromCharacterMap(normalizeCharacterMap(merge主角.当前互动角色), out);
  // 根级 / stat_data / mvu（与运行时合并后常见结构）
  pushRaceStringsFromCharacterMap(normalizeCharacterMap(v?.当前互动角色), out);
  pushRaceStringsFromCharacterMap(normalizeCharacterMap(v?.stat_data?.当前互动角色), out);
  pushRaceStringsFromCharacterMap(normalizeCharacterMap(v?.mvu?.当前互动角色), out);

  const followers = normalizeCharacterMap(
    v?.追随者与猎物 ??
      merge主角.追随者与猎物 ??
      v?.stat_data?.追随者与猎物 ??
      v?.mvu?.追随者与猎物,
  );
  pushRaceStringsFromCharacterMap(followers, out);
  return out;
}

function collectRaceStringsFromVariables(): string[] {
  const merged = new Set<string>();
  const tryOne = (v: any) => {
    for (const s of collectRaceStringsFromVariableRoot(v)) merged.add(s);
  };
  try {
    const g = globalThis as any;
    if (g?.Mvu && typeof g.Mvu.getMvuData === 'function') {
      tryOne(g.Mvu.getMvuData({ type: 'message', message_id: 'latest' }));
      const lastId = getLastMessageId();
      if (lastId >= 0) tryOne(g.Mvu.getMvuData({ type: 'message', message_id: lastId }));
    }
  } catch {
    /* ignore */
  }
  const scopes: Array<Parameters<typeof getVariables>[0]> = [
    { type: 'message', message_id: 'latest' },
    { type: 'chat' },
    { type: 'character' },
    { type: 'global' },
  ];
  for (const scope of scopes) {
    try {
      tryOne(getVariables(scope));
    } catch {
      /* ignore */
    }
  }
  return [...merged];
}

function isRaceManagedEntry(entryName: string): boolean {
  return RACE_LIGHT_RULES.some(r => r.entryNameIncludes && entryName.includes(r.entryNameIncludes));
}

function getStrategyTypeForRaceEntry(
  entryName: string,
  raceStrings: string[],
  recentTexts: string[],
  lastTexts: string[],
): WorldbookEntry['strategy']['type'] | null {
  const rule = RACE_LIGHT_RULES.find(r => r.entryNameIncludes && entryName.includes(r.entryNameIncludes));
  if (!rule) return null;
  const varHit = raceStrings.some(raceStr =>
    rule.matchSubstrings.some(sub => Boolean(sub) && raceStr.includes(sub)),
  );
  const chatKeywords = rule.keywords?.length ? rule.keywords : rule.matchSubstrings;
  const chatSource = RACE_CHAT_KEYWORDS_LAST_MESSAGE_ONLY ? lastTexts : recentTexts;
  const chatHit = keywordHitInTexts(chatSource, chatKeywords);
  const active = varHit || chatHit;
  if (DEBUG_TRACE && (varHit || chatHit)) {
    kwTrace(`种族条目命中 name=${entryName} varHit=${varHit} chatHit=${chatHit}`);
  }
  return active ? 'constant' : 'selective';
}

function getStrategyTypeForHunterLevelEntry(
  entryName: string,
  hunterLevel: string,
  trigger: { recentHit: boolean; lastHit: boolean },
): WorldbookEntry['strategy']['type'] | null {
  if (!entryName.includes('猎人等级-')) return null;
  const lv = hunterLevel.toUpperCase();
  const allow = new Set(['D', 'C', 'B', 'A', 'S', 'SS']);
  const normalized = allow.has(lv) ? lv : 'D';
  const target = `猎人等级-${normalized}`;
  // 只允许控制「猎人等级-*」：非目标等级永远绿灯
  if (!entryName.includes(target)) return 'selective';
  // 目标等级条目：只有触发命中才蓝灯；否则绿灯
  return trigger.recentHit || trigger.lastHit ? 'constant' : 'selective';
}

async function syncWorldbookByKeywords(): Promise<void> {
  const wbName = resolvePrimaryWorldbookName();
  if (!wbName) {
    if (lastWorldbookWarn !== 'no_primary') {
      lastWorldbookWarn = 'no_primary';
      console.warn('[关键字世界书] 当前角色未绑定主世界书，已跳过。请在角色卡中绑定世界书。');
    }
    return;
  }
  lastWorldbookWarn = null;

  const hunterLevel = getWorldHunterLevel();
  const worldLocation = getWorldLocation();
  const questStatus = getWorldQuestStatus();
  const combatStyleQuest = getProtagonistCombatStyleAndRanks();
  const currentStyleLabel = getProtagonistCurrentStyleLabelForWorldbook();
  const raceStrings = collectRaceStringsFromVariables();
  kwTrace(`种族变量扫描: ${raceStrings.length ? raceStrings.join(' | ') : '(无)'}`);
  kwTrace(
    `Dark战斗风格×委托: 当前风格=${currentStyleLabel || '(空)'} 战斗风格=${combatStyleQuest.style || '(空)'} 阶位=${JSON.stringify(combatStyleQuest.ranks)} 委托=${questStatus || '(空)'} 有任务ctx=${hasQuestContextForCombatStyleEntries(questStatus)}`,
  );
  // recent 文本：RULES / 种族聊天关键字（用户+AI）
  const recentTexts = getRecentMessageTexts(SCAN_LAST_MESSAGES);
  const recentUserTexts = getRecentUserMessageTexts(SCAN_LAST_MESSAGES);
  // last 文本：给 scanMode=last 的规则用
  const lastAnyText = getLastAnyMessageText();
  const lastTexts = lastAnyText ? [lastAnyText] : [];
  // 猎人等级条目触发：只影响「猎人等级-*」条目
  const hunterRecentHit = keywordHitInTexts(recentTexts, HUNTER_LEVEL_TRIGGER_RECENT_KEYWORDS);
  const hunterLastHit = keywordHitInTexts(lastTexts, HUNTER_LEVEL_TRIGGER_LAST_KEYWORDS);
  kwLog('主世界书:', wbName, '近期消息数:', recentTexts.length, 'last是否为空:', !lastAnyText, '当前位置:', worldLocation || '(空)');

  await updateWorldbookWith(wbName, entries => {
    let changed = 0;
    for (const e of entries) {
      if (!e.enabled) continue;
      const name = e.name ?? '';
      if (!isManagedEntry(name)) continue;

      // 1) 变量 + 关键词触发：只控制「猎人等级-*」条目
      const hunterType = getStrategyTypeForHunterLevelEntry(name, hunterLevel, { recentHit: hunterRecentHit, lastHit: hunterLastHit });
      if (hunterType) {
        if (e.strategy.type !== 'vectorized' && e.strategy.type !== hunterType) {
          e.strategy = { ...e.strategy, type: hunterType };
          changed++;
          kwLog(`条目「${name}」→ ${hunterType} (猎人等级=${hunterLevel || 'D'})`);
        }
        continue;
      }

      // 1.25) Dark：「剑圣风格1」等 — 委托执行中 + 当前风格阶位与条目一致 → 蓝灯
      const combatStyleQuestType = getStrategyTypeForCombatStyleQuestEntry(
        name,
        combatStyleQuest.style,
        combatStyleQuest.ranks,
        questStatus,
        currentStyleLabel,
      );
      if (combatStyleQuestType !== null) {
        if (e.strategy.type !== 'vectorized' && e.strategy.type !== combatStyleQuestType) {
          e.strategy = { ...e.strategy, type: combatStyleQuestType };
          changed++;
          kwTrace(
            `条目切换 name=${name} to=${combatStyleQuestType} (战斗风格×委托 style=${combatStyleQuest.style} quest=${questStatus})`,
          );
          kwLog(`条目「${name}」→ ${combatStyleQuestType} (战斗风格×委托)`);
        }
        continue;
      }

      // 1.5) 「种族-*」：变量 种族 + 聊天关键字（范围由 RACE_CHAT_KEYWORDS_LAST_MESSAGE_ONLY 决定）
      const raceType = getStrategyTypeForRaceEntry(name, raceStrings, recentTexts, lastTexts);
      if (raceType !== null) {
        if (e.strategy.type !== 'vectorized' && e.strategy.type !== raceType) {
          const prevType = e.strategy.type;
          e.strategy = { ...e.strategy, type: raceType };
          changed++;
          kwTrace(`条目切换 name=${name} from=${prevType} to=${raceType} (种族)`);
          kwLog(`条目「${name}」→ ${raceType} (种族)`);
        }
        continue;
      }

      // 2) 变量驱动：当前委托状态条目由 世界.委托状态 控制
      if (name.includes('当前委托状态') || name.includes('委托完成检测')) {
        const nextByQuestStatus: WorldbookEntry['strategy']['type'] = isQuestActiveForCombatStyleEntries(questStatus)
          ? 'constant'
          : 'selective';
        if (e.strategy.type !== 'vectorized' && e.strategy.type !== nextByQuestStatus) {
          const prevType = e.strategy.type;
          e.strategy = { ...e.strategy, type: nextByQuestStatus };
          changed++;
          kwTrace(`条目切换 name=${name} from=${prevType} to=${nextByQuestStatus} (委托状态=${questStatus || '(空)'})`);
          kwLog(`条目「${name}」→ ${nextByQuestStatus} (委托状态=${questStatus || '(空)'})`);
        }
        continue;
      }

      // 2.5) 任务进行中时，发布地点条目强制绿灯，避免“路过+关键词”重复触发发布
      if (name.includes('地点-午夜玫瑰酒馆') && isQuestActiveForCombatStyleEntries(questStatus)) {
        if (e.strategy.type !== 'vectorized' && e.strategy.type !== 'selective') {
          const prevType = e.strategy.type;
          e.strategy = { ...e.strategy, type: 'selective' };
          changed++;
          kwTrace(`条目切换 name=${name} from=${prevType} to=selective (委托状态=执行中，强制关闭发布地点)`);
        }
        continue;
      }

      const matchedRuleIdx = RULES.findIndex(r => r.entryNameIncludes && name.includes(r.entryNameIncludes));
      const rule = matchedRuleIdx >= 0 ? RULES[matchedRuleIdx] : null;
      const mode = rule?.scanMode ?? 'recent';
      const ctx: KeywordScanContext = { recentTexts, recentUserTexts, lastTexts, worldLocation };
      const textsToUse = rule ? getTextsByScanMode(mode, ctx) : [];
      if (rule && DEBUG_TRACE) {
        const hit = ruleHitByMode(rule, ctx);
        kwTrace(
          `规则检查 entry=${name} mode=${mode} keywords=${rule.keywords.join('|')} source=${textsToUse.join(' || ') || '(空)'} location=${worldLocation || '(空)'} hit=${hit}`,
        );
      }
      const nextType = getNextStrategyTypeForEntry(name, ctx);
      if (!nextType) continue;
      if (e.strategy.type === nextType) continue;

      /** 向量化条目勿动 */
      if (e.strategy.type === 'vectorized') continue;

      const prevType = e.strategy.type;
      e.strategy = { ...e.strategy, type: nextType };
      changed++;
      kwTrace(`条目切换 name=${name} from=${prevType} to=${nextType}`);
      kwLog(`条目「${name}」→ ${nextType}`);
    }
    if (DEBUG && changed === 0) kwLog('无需变更');
    return entries;
  });
}

function scheduleSync(): void {
  if (debounceTimer) clearTimeout(debounceTimer);
  debounceTimer = setTimeout(() => {
    debounceTimer = null;
    void errorCatched(syncWorldbookByKeywords)();
  }, DEBOUNCE_MS);
}

/** Dark iframe 写变量后 MVU 可能晚一拍提交；在防抖之外再补两次直跑，避免必须发消息才亮灯 */
let darkBurstTimer1: ReturnType<typeof setTimeout> | null = null;
let darkBurstTimer2: ReturnType<typeof setTimeout> | null = null;
function scheduleDarkResyncBurst(): void {
  scheduleSync();
  if (darkBurstTimer1) clearTimeout(darkBurstTimer1);
  if (darkBurstTimer2) clearTimeout(darkBurstTimer2);
  darkBurstTimer1 = setTimeout(() => {
    darkBurstTimer1 = null;
    void errorCatched(syncWorldbookByKeywords)();
  }, 700);
  darkBurstTimer2 = setTimeout(() => {
    darkBurstTimer2 = null;
    void errorCatched(syncWorldbookByKeywords)();
  }, 1600);
}

$(() => {
  errorCatched(() => {
    console.info('[关键字世界书] 已加载；规则数:', RULES.length);
    void syncWorldbookByKeywords();

    // Dark 状态栏在 iframe 内 replaceMvuData 后，MVU 会触发；与 MESSAGE_UPDATED 互补
    void waitGlobalInitialized('Mvu')
      .then(() => attachMvuVariableEndedListenerOnce())
      .catch(() => {
        /* 未安装 MVU 时忽略 */
      });

    // Dark 面板 mirror 到聊天变量后主动派发（见 src/Dark/App.tsx notifyParentWorldbookStrategySync）
    $(window).on('dark_worldbook_resync_needed', () => {
      kwLog('dark_worldbook_resync_needed → 调度同步（含延迟补跑）');
      scheduleDarkResyncBurst();
    });

    eventOn(tavern_events.MESSAGE_SENT, () => {
      updateMissingCountsByLastAnyMessage();
      kwLog('MESSAGE_SENT → 调度同步');
      scheduleSync();
    });
    eventOn(tavern_events.MESSAGE_RECEIVED, () => {
      updateMissingCountsByLastReceived();
      updateMissingCountsByLastAnyMessage();
      kwLog('MESSAGE_RECEIVED → 调度同步');
      scheduleSync();
    });
    eventOn(tavern_events.CHARACTER_PAGE_LOADED, () => {
      kwLog('CHARACTER_PAGE_LOADED → 调度同步');
      void waitGlobalInitialized('Mvu')
        .then(() => attachMvuVariableEndedListenerOnce())
        .catch(() => {});
      scheduleSync();
    });
    eventOn(tavern_events.CHAT_CHANGED, () => {
      kwLog('CHAT_CHANGED → 调度同步');
      scheduleSync();
    });
    // Dark 状态栏等在 iframe 内 replaceMvuData / 改楼层变量时不会触发 SENT/RECEIVED，但通常会触发 MESSAGE_UPDATED
    eventOn(tavern_events.MESSAGE_UPDATED, () => {
      kwLog('MESSAGE_UPDATED → 调度同步');
      scheduleSync();
    });

    $(window).on('pagehide', () => {
      if (debounceTimer) {
        clearTimeout(debounceTimer);
        debounceTimer = null;
      }
    });
  })();
});
